const recs = (n) => $(n).all().flatMap((it) => (it.json && it.json.records) || []);
const proyectos = recs('Leer Proyectos');
const voces = recs('Leer Voces');
const keywords = recs('Leer Keywords');
const referentes = recs('Leer Referentes');
const _nrm = (s) => (s||'').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/\s+/g,' ').trim();
const cfg0 = $('Config').first().json;
const AJUSTE_MAP = { 'peso de vistas':'peso_views', 'peso de likes':'peso_likes', 'peso de interaccion':'peso_eng', 'peso de relevancia':'peso_relevancia', 'bonus idioma extranjero':'boost_idioma', 'seguidores para marcar viral':'umbral_viral', 'minimo de vistas':'min_views', 'minimo de likes':'min_likes', 'relevancia minima':'min_relevancia', 'candidatos por corrida':'top_n', 'dias de recencia':'dias_recencia', 'resultados por cuenta de referente':'resultados_referente', 'buscar por referentes en instagram':'buscar_referente_ig', 'buscar por referentes en tiktok':'buscar_referente_tiktok', 'buscar por keywords en tiktok':'buscar_keyword_tiktok', 'resultados por keyword':'resultados_keyword' };
const ajustes = {};
recs('Leer Ajustes').forEach(a => { const f = a.fields || {}; const key = AJUSTE_MAP[_nrm(f.clave)]; if (key && f.valor !== undefined && f.valor !== null && f.valor !== '') ajustes[key] = Number(f.valor); });

// Knobs de ejecucion GLOBALES (ADR-016): ajustes (equipo) > Config (default). Topes dev-only en Config.
const pick = (k, d) => (ajustes[k] != null ? ajustes[k] : (cfg0[k] != null ? Number(cfg0[k]) : d));
const dias_recencia = Number(pick('dias_recencia', 7));
const top_n = Number(pick('top_n', 100));
const cap_rr = Number(cfg0.cap_resultados_referente || 0);
const rr_raw = Number(pick('resultados_referente', 20));
const resultados_referente = cap_rr > 0 ? Math.min(rr_raw, cap_rr) : rr_raw; // cap max (ADR-016)
const cap_top_n = Number(cfg0.cap_top_n || 0);
// Knob propio del eje keyword + cap dev-only (ADR-017): descubrimiento ciego = volumen mas chico, topeado.
const cap_rk = Number(cfg0.cap_resultados_keyword || 0);
const rk_raw = Number(pick('resultados_keyword', 10));
const resultados_keyword = cap_rk > 0 ? Math.min(rk_raw, cap_rk) : rk_raw;
// Toggles de eje (ADR-017): ajustes (equipo) > Config. Default ON. Referentes ambas plataformas + keyword TikTok.
const BUSCAR_REF_IG = Number(pick('buscar_referente_ig', 1)) > 0;
const BUSCAR_REF_TT = Number(pick('buscar_referente_tiktok', 1)) > 0;
const FLAG_KW = Number(pick('buscar_keyword_tiktok', 1)) > 0; // eje TikTok-keyword reactivado como toggle (ADR-017)

const vozById = {};
const vozCritById = {};
voces.forEach(v => { const vf = v.fields || {}; vozById[v.id] = vf.nombre || ''; vozCritById[v.id] = (vf.criterios_relevancia || '').toString().trim(); });

const projects = {};
proyectos.forEach(p => {
  const f = p.fields || {};
  const vozId = Array.isArray(f.voz_default) && f.voz_default[0] ? f.voz_default[0] : null;
  projects[p.id] = {
    id: p.id, nombre: f.nombre || '',
    voz_id: vozId, voz_nombre: vozId && vozById[vozId] ? vozById[vozId] : '',
    criterios: (f.criterios_relevancia || '').toString().trim(),
    voz_criterios: vozId && vozCritById[vozId] ? vozCritById[vozId] : '',
    keywords: [], ig_handles: [], tt_handles: []
  };
});
keywords.forEach(k => {
  const f = k.fields || {}; if (!f.termino) return;
  (Array.isArray(f.proyecto) ? f.proyecto : []).forEach(proy => { if (projects[proy]) projects[proy].keywords.push(String(f.termino).trim()); });
});
referentes.forEach(r => {
  const f = r.fields || {};
  const handle = String(f.handle || '').trim().replace(/^@/, '');
  if (!handle) return;
  const plat = String(f.plataforma || '').toLowerCase();
  (Array.isArray(f.proyecto) ? f.proyecto : []).forEach(proy => {
    if (!projects[proy]) return;
    if (plat.indexOf('insta') >= 0) projects[proy].ig_handles.push(handle);
    else if (plat.indexOf('tik') >= 0) projects[proy].tt_handles.push(handle);
  });
});

const ig_urls = []; const ig_owner_to_proj = {};
const tt_profiles = []; const tt_owner_to_proj = {};
const tt_hashtags = []; const kw_to_proj = {};
Object.values(projects).forEach(p => {
  // Referente: IG por cuenta (directUrls), TikTok por perfil (profiles). Gateado por toggle (ADR-017).
  if (BUSCAR_REF_IG) p.ig_handles.forEach(h => { ig_urls.push('https://www.instagram.com/' + h + '/'); (ig_owner_to_proj[h.toLowerCase()] = ig_owner_to_proj[h.toLowerCase()] || []).push(p.id); });
  if (BUSCAR_REF_TT) p.tt_handles.forEach(h => { tt_profiles.push(h); (tt_owner_to_proj[h.toLowerCase()] = tt_owner_to_proj[h.toLowerCase()] || []).push(p.id); });
  // Keyword TikTok: eje reactivado como toggle (ADR-017). Solo se arma si buscar_keyword_tiktok on. IG-keyword retirado.
  if (FLAG_KW) p.keywords.forEach(k => { const kk = k.replace(/^#/, '').toLowerCase().replace(/\s+/g, ''); if (!kk) return; (kw_to_proj[kk] = kw_to_proj[kk] || []).push(p.id); tt_hashtags.push(kk); });
});

return [{ json: {
  projects, ig_urls: [...new Set(ig_urls)], tt_profiles: [...new Set(tt_profiles)],
  ig_hashtags: [], tt_hashtags: [...new Set(tt_hashtags)],
  ig_owner_to_proj, tt_owner_to_proj, kw_to_proj, active_project_ids: Object.keys(projects),
  dias_recencia, resultados_referente, resultados_keyword, top_n, cap_top_n, ajustes
} }];

// #24: un item por referente IG -> el Apify IG Reels corre 1 vez por cuenta,
// cada llamada con su propio cupo (resultsLimit deja de ser global). Reparte equitativo.
const urls = ($('Armar plan de corrida').first().json.ig_urls) || [];
return urls.map(u => ({ json: { ig_url: u } }));

const item = $input.item.json;
// Solo reels/videos: IG trae fotos y carruseles que no se pueden transcribir; descartar lo que no sea video.
if (item.type && item.type !== 'Video') { return null; }
// Stub de un eje vacío (IG-Hashtag con 0 URLs devuelve {error:'no_items'}): sin id ni url -> descartar.
if (!(item.id || item.shortCode || item.shortcode) && !item.url) { return null; }
const seguidores = item.followersCount || item.ownerFollowersCount || (item.metaData && item.metaData.followersCount) || 0;
return { json: {
  plataforma: 'instagram',
  external_id: String(item.id || item.shortCode || item.shortcode || ''),
  username: item.ownerUsername || '',
  nombre: item.ownerFullName || '',
  seguidores,
  bio: item.biography || item.ownerBio || (item.metaData && item.metaData.biography) || '',
  descripcion: item.caption || '',
  likes: item.likesCount || 0,
  comentarios: item.commentsCount || 0,
  reproducciones: item.videoViewCount || item.videoPlayCount || item.igPlayCount || 0,
  url: item.url || '',
  video_url: item.url || '',
  thumbnail_url: item.displayUrl || '',
  hashtags: (item.hashtags || []).join(', '),
  duracion_video: item.videoDuration || 0,
  engagement_rate: seguidores > 0 ? (((item.likesCount || 0) + (item.commentsCount || 0)) / seguidores * 100).toFixed(2) : '0',
  fecha_publicacion: (function(){ var d = new Date(item.timestamp); return isNaN(d.getTime()) ? '' : d.toISOString().split('T')[0]; })()
} };

const item = $input.item.json;
// Stub de un eje vacío (TikTok-Perfil con 0 referentes devuelve {}): sin id ni url -> descartar.
if (!item.id && !item.webVideoUrl) { return null; }
const am = item.authorMeta || {};
const seguidores = am.fans || 0;
return { json: {
  plataforma: 'tiktok',
  idioma_nativo: (item.textLanguage && item.textLanguage !== 'un') ? String(item.textLanguage).toLowerCase().slice(0, 2) : '',
  external_id: String(item.id || ''),
  username: am.name || '',
  nombre: am.nickName || '',
  seguidores,
  bio: am.signature || '',
  descripcion: item.text || item.desc || '',
  likes: item.diggCount || 0,
  comentarios: item.commentCount || 0,
  reproducciones: item.playCount || 0,
  url: item.webVideoUrl || '',
  video_url: item.webVideoUrl || '',
  thumbnail_url: (item.videoMeta && item.videoMeta.coverUrl) || '',
  hashtags: (item.hashtags || []).map(function (h) { return h.name || h; }).join(', '),
  duracion_video: item.videoMeta ? (item.videoMeta.duration || 0) : 0,
  engagement_rate: seguidores > 0 ? (((item.diggCount || 0) + (item.commentCount || 0)) / seguidores * 100).toFixed(2) : '0',
  fecha_publicacion: item.createTimeISO ? item.createTimeISO.split('T')[0] : ''
} };

const plan = $('Armar plan de corrida').first().json;
const projects = plan.projects, ig_owner = plan.ig_owner_to_proj || {}, tt_owner = plan.tt_owner_to_proj || {}, kw = plan.kw_to_proj || {};
const activeIds = plan.active_project_ids || [];
const DIAS = Number(plan.dias_recencia || 0); // recencia global (ADR-016)
const out = [];
for (const it of $input.all()) {
  const d = it.json;
  if (!d.url) continue;
  const u = String(d.username || '').toLowerCase().replace(/^@/, '');
  // Fan-out (ADR-013): un mismo video puede ser reclamado por varios proyectos activos a la vez.
  // claims: proyecto_id -> tema. El referente (cuenta sembrada) reclama con tema=''; la keyword
  // aporta el termino matcheado. 'pid in claims' (no truthiness) preserva el '' del referente
  // y deja que la keyword reclame SOLO los proyectos que el referente no reclamo.
  const claims = {};
  const ownerList = (d.plataforma || '') === 'instagram' ? (ig_owner[u] || [])
                  : (d.plataforma || '') === 'tiktok' ? (tt_owner[u] || []) : [];
  ownerList.forEach(pid => { if (!(pid in claims)) claims[pid] = ''; });
  const tags = String(d.hashtags || '').toLowerCase().split(',').map(s => s.trim().replace(/^#/, '').replace(/\s+/g, '')).filter(Boolean);
  for (const t of tags) { (kw[t] || []).forEach(pid => { if (!(pid in claims)) claims[pid] = t; }); }
  // fallback: si nada lo reclamo y hay UN solo proyecto activo, se lo lleva ese.
  let pids = Object.keys(claims);
  if (!pids.length && activeIds.length === 1) { claims[activeIds[0]] = ''; pids = [activeIds[0]]; }
  for (const proyId of pids) {
    const p = projects[proyId];
    if (!p) continue;
    // guardia de recencia (capa 2): descarta lo mas viejo que dias_recencia del proyecto.
    // 0 = sin limite. Si no hay fecha, se conserva (no se puede juzgar la edad).
    if (DIAS > 0 && d.fecha_publicacion) {
      const ts = Date.parse(d.fecha_publicacion);
      if (Number.isFinite(ts) && (Date.now() - ts) > DIAS * 86400000) continue;
    }
    out.push({ json: Object.assign({}, d, {
      proyecto_id: proyId, proyecto_nombre: p.nombre, voz_id: p.voz_id, voz_nombre: p.voz_nombre,
      _tema: claims[proyId]
    }) });
  }
}
return out;

// Pre-trim de relevancia (Haiku) — colador LAXO sobre el caption, ANTES de transcribir.
// Optimiza recall: descarta solo lo OBVIAMENTE off-topic. Fail-open (si Haiku falla, pasa todo).
// Caption pobre (sin texto real): eje referente pasa sin juicio, eje keyword se descarta directo.
const KEY = '<ANTHROPIC_API_KEY>';
const plan = $('Armar plan de corrida').first().json || {};
const projects = plan.projects || {};
const items = $('Asignar proyecto+voz').all().map(i => i.json);

const byProj = {};
items.forEach(d => { (byProj[d.proyecto_id] = byProj[d.proyecto_id] || []).push(d); });

const drop = new Set();
for (const pid in byProj) {
  const arr = byProj[pid];
  const p = projects[pid] || {};
  const critProy = (p.criterios || '').toString().trim();
  const critVoz = (p.voz_criterios || '').toString().trim();
  const criterios = [critProy, critVoz].filter(Boolean).join('\n').trim();
  const criteriosTxt = [critProy ? 'CRITERIOS DE TEMA (principal):\n' + critProy : '', critVoz ? 'AJUSTE DE VOZ (complementa, no manda):\n' + critVoz : ''].filter(Boolean).join('\n\n');
  if (!criterios) continue; // sin rúbrica no se juzga: no se descarta nada
  // Caption pobre = sin evidencia para juzgar (fix calidad run 07-09). Eje referente (fuente curada,
  // _tema=''): pasa SIN juicio -> lo juzga el gate con el transcript. Eje keyword (descubrimiento
  // ciego): descarte directo, un caption de puro hashtag no prueba nada.
  const _senal = (d) => String(d.descripcion || '').replace(/https?:\/\/\S+/g, ' ').replace(/[#@]\S+/g, ' ').replace(/[^\p{L}\p{N}?!.,;: ]/gu, ' ').replace(/\s+/g, ' ').trim();
  const _judge = [];
  let _exentos = 0, _pobresKw = 0;
  for (const d of arr) {
    if (!String(d.external_id || '')) continue;
    if (_senal(d).length < 25) { if (d._tema) { drop.add(pid + '|' + String(d.external_id)); _pobresKw++; } else { _exentos++; } continue; }
    _judge.push(d);
  }
  if (_exentos || _pobresKw) console.log('[Pre-trim] captions pobres pid=' + pid + ': ' + _exentos + ' exentos (referente, pasan al gate), ' + _pobresKw + ' descartados (keyword)');
  const lote = _judge.map(d => ({
    id: String(d.external_id || ''),
    texto: (String(d.descripcion || '') + ' ' + String(d.hashtags || '')).replace(/\s+/g, ' ').trim().slice(0, 500)
  })).filter(x => x.id);
  if (!lote.length) continue;
  const sys = 'Sos un filtro de relevancia LAXO. Te doy el tema de un proyecto, sus criterios (el TEMA manda; el AJUSTE DE VOZ solo complementa), y una lista de videos (id + texto del caption). Devolve UNICAMENTE un JSON {"descartar":[ids]} con los ids OBVIAMENTE fuera de tema. En la duda NO descartes (preferimos dejar pasar de mas). No expliques nada.';
  const usr = 'TEMA: ' + (p.nombre || '') + '\n' + criteriosTxt + '\n\nVIDEOS:\n' + JSON.stringify(lote);
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: { 'x-api-key': KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: { model: 'claude-haiku-4-5', max_tokens: 1000, system: sys, messages: [{ role: 'user', content: usr }] },
      json: true,
      timeout: 30000
    });
    let txt = '';
    try { txt = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
    const m = String(txt).match(/\{[\s\S]*\}/);
    if (m) { const parsed = JSON.parse(m[0]); (parsed.descartar || []).forEach(id => drop.add(pid + '|' + String(id))); }
  } catch (e) { /* fail-open: no se descarta nada de este proyecto */ }
}

const _desc = [...drop];
console.log('[Pre-trim] descartados off-topic: ' + _desc.length + '/' + items.length + (_desc.length ? ' -> ' + _desc.join(', ') : ''));
const out = [];
for (const d of items) { if (!drop.has(String(d.proyecto_id) + '|' + String(d.external_id || ''))) out.push({ json: d }); }
return out;

const cfg = Object.assign({}, $('Config').first().json, ($('Armar plan de corrida').first().json.ajustes || {}));
const rows = (n) => { const a = $(n).all().map(i => i.json); if (a.length === 1 && Array.isArray(a[0])) return a[0]; return a; };
const items = $('Pre-trim relevancia').all().map(i => i.json);
const seen = new Set(rows('Leer procesados').map(r => r && String(r.external_id)).filter(Boolean));
const signal = {};
rows('Leer señal selección').forEach(r => { if (r && r.referente !== undefined) signal[(r.referente || '') + '|' + (r.idioma || '')] = Number(r.tasa_seleccion || 0); });
const signalTema = {};
rows('Leer señal tema').forEach(r => { if (r && r.tema) signalTema[String(r.tema)] = Number(r.tasa_seleccion || 0); });

const norm = (s) => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const DICT = {
  es: [' el ', ' la ', ' los ', ' las ', ' que ', ' de ', ' para ', ' con ', ' una ', ' como ', ' pero ', ' esto '],
  en: [' the ', ' and ', ' you ', ' for ', ' with ', ' this ', ' that ', ' your ', ' are ', ' have ', ' what '],
  pt: [' uma ', ' voce ', ' nao ', ' isso ', ' mais ', ' como ', ' obrigado ', ' entao ', ' muito '],
  it: [' il ', ' che ', ' per ', ' una ', ' questo ', ' come ', ' sono ', ' non ', ' anche ', ' molto '],
  fr: [' les ', ' une ', ' pour ', ' avec ', ' vous ', ' est ', ' pas ', ' comme ', ' dans ', ' mais '],
  de: [' der ', ' die ', ' und ', ' ist ', ' nicht ', ' ein ', ' mit ', ' das ', ' ich ', ' auch '],
  nl: [' het ', ' een ', ' van ', ' ik ', ' niet ', ' met ', ' dat ', ' zijn ', ' voor ', ' ook ']
};
// scripts no-latinos: evidencia directa de NO-español (caen a 'ot' -> reciben boost)
const NONLATIN = /[\u3040-\u30ff\u4e00-\u9fff\uac00-\ud7af\u0400-\u04ff\u0600-\u06ff\u0590-\u05ff\u0900-\u097f\u0e00-\u0e7f\u0370-\u03ff]/;
const guessLang = (raw) => {
  const orig = (raw || '').toString();
  if (NONLATIN.test(orig)) return 'ot';
  const t = ' ' + norm(orig) + ' '; let best = '', bestN = 0;
  for (const lng in DICT) { let n = 0; DICT[lng].forEach(w => { if (t.indexOf(w) >= 0) n++; }); if (n > bestN) { bestN = n; best = lng; } }
  if (bestN > 0) return best;
  // sin stopwords reconocidas: marcas fuertes de español -> es; si no, desconocido -> 'ot' (premia no-español)
  if (/[ñ¿¡áéíóú]/.test(orig.toLowerCase())) return 'es';
  return 'ot';
};
const pct = (arr, v) => { if (arr.length <= 1) return 1; let c = 0; for (const x of arr) if (x <= v) c++; return c / arr.length; };

const byProj = {};
items.forEach(d => { (byProj[d.proyecto_id] = byProj[d.proyecto_id] || []).push(d); });
const out = [];
for (const pid in byProj) {
  const arr = byProj[pid];
  const views = arr.map(d => Number(d.reproducciones || 0));
  const likes = arr.map(d => Number(d.likes || 0));
  const engs = arr.map(d => parseFloat(d.engagement_rate) || 0);
  const scored = arr.map(d => {
    const v = Number(d.reproducciones || 0), l = Number(d.likes || 0), e = parseFloat(d.engagement_rate) || 0;
    const idioma = d.idioma_nativo || guessLang((d.descripcion || '') + ' ' + (d.bio || ''));
    const idiomaBoost = idioma !== 'es' ? Number(cfg.boost_idioma || 0.3) : 0;
    const selRef = signal[(d.username || '') + '|' + idioma] || 0;
    const selTema = signalTema[String(d._tema || '')] || 0;
    const sel = Math.max(selRef, selTema); // bi-eje (O7): referente o keyword/tema
    const base = Number(cfg.peso_views || 0.4) * pct(views, v) + Number(cfg.peso_likes || 0.4) * pct(likes, l) + Number(cfg.peso_eng || 0.2) * pct(engs, e);
    const heat = base * (1 + idiomaBoost) * (1 + sel);
    return Object.assign({}, d, {
      idioma_guess: idioma, heat_score: Math.round(heat * 10000) / 10000,
      viral_por_tamano: Number(d.seguidores || 0) > Number(cfg.umbral_viral || 700000)
    });
  });
  const MIN_V = Number(cfg.min_views || 0), MIN_L = Number(cfg.min_likes || 0);
  const fresh = scored.filter(d => !seen.has(String(d.external_id)) && Number(d.reproducciones || 0) >= MIN_V && Number(d.likes || 0) >= MIN_L);
  fresh.sort((a, b) => b.heat_score - a.heat_score);
  fresh.forEach(d => out.push({ json: d })); // ADR-016: sin corte por proyecto; se transcribe todo
}
// cap_top_n (dev-only): techo duro de transcripcion por corrida (protege backfill).
// ADR-016: cuenta VIDEOS DISTINTOS por heat, no filas (video,proyecto); el fan-out no consume cupo.
const CAP = Number($('Config').first().json.cap_top_n || 0);
if (CAP > 0) { out.sort((a, b) => (b.json.heat_score || 0) - (a.json.heat_score || 0)); const keepIds = new Set(); const capped = []; for (const it of out) { const id = String(it.json.external_id || ''); if (!id) { capped.push(it); continue; } if (!keepIds.has(id)) { if (keepIds.size >= CAP) continue; keepIds.add(id); } capped.push(it); } return capped; }
return out;

// Transcribir (Supadata) — dedup intra-corrida (ADR-016): cada external_id se transcribe UNA vez y
// el transcript se reparte a TODAS las copias (fan-out). external_id atado al item (#8). lang de
// Supadata primario; fallback adivina sobre el TRANSCRIPT (#7). Fail-open: si falla, transcripcion vacia.
const KEY = '<SUPADATA_API_KEY>';
const SLEEP_MS = 1000;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));
const norm = (s) => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const DICT = {
  es: [' el ',' la ',' que ',' de ',' para ',' con ',' una ',' como ',' pero ',' esto '],
  en: [' the ',' and ',' you ',' for ',' with ',' this ',' that ',' your ',' are ',' what '],
  pt: [' uma ',' voce ',' nao ',' isso ',' mais ',' como ',' entao ',' muito '],
  it: [' il ',' che ',' per ',' una ',' questo ',' come ',' sono ',' non ',' molto '],
  fr: [' les ',' une ',' pour ',' avec ',' vous ',' est ',' pas ',' comme ',' mais ']
};
const guessLang = (txt) => {
  const t = ' ' + norm(txt) + ' '; let best = '', bestN = 0;
  for (const lng in DICT) { let n = 0; DICT[lng].forEach(p => { if (t.indexOf(p) >= 0) n++; }); if (n > bestN) { bestN = n; best = lng; } }
  return bestN === 0 ? '' : best;
};
const items = $input.all();
// 1) videos distintos por external_id (url de respaldo)
const order = []; const firstUrl = {};
for (const it of items) { const d = it.json; const id = String(d.external_id || d.url || ''); if (!id) continue; if (!(id in firstUrl)) { firstUrl[id] = d.video_url || d.url || ''; order.push(id); } }
console.log(`[Transcribir] ${items.length} items / ${order.length} videos distintos`);
// 2) transcribir cada distinto UNA vez
const cache = {}; const loopStart = Date.now();
for (let i = 0; i < order.length; i++) {
  const id = order[i]; const url = firstUrl[id];
  let txt = '', lang = '';
